B.OV=new A.bM(B.fq,["\u03a4\u03bf \u03b8\u03c5\u03bc\u03ac\u03c1\u03b9 (Thymus Vulgaris) \u03b5\u03af\u03bd\u03b1\u03b9 \u03ad\u03bd\u03b1 \u03c0\u03bf\u03bb\u03c5\u03b5\u03c4\u03ad\u03c2 \u03c6\u03c5\u03c4\u03cc \u03bc\u03b5 \u03c7\u03b1\u03bc\u03b7\u03bb\u03ad\u03c2 \u03b1\u03c0\u03b1\u03b9\u03c4\u03ae\u03c3\u03b5\u03b9\u03c2 \u03c3\u03b5 \u03bd\u03b5\u03c1\u03cc \u03ba\u03b1\u03b9 \u03c5\u03c8\u03b7\u03bb\u03ad\u03c2 \u03b1\u03c0\u03b1\u03b9\u03c4\u03ae\u03c3\u03b5\u03b9\u03c2 \u03c3\u03b5 \u03b7\u03bb\u03b9\u03b1\u03ba\u03cc \u03c6\u03c9\u03c2. \u0395\u03c5\u03b4\u03bf\u03ba\u03b9\u03bc\u03b5\u03af \u03c3\u03b5 \u03c6\u03c4\u03c9\u03c7\u03ac \u03b5\u03b4\u03ac\u03c6\u03b7. \u03a7\u03c1\u03b7\u03c3\u03b9\u03bc\u03bf\u03c0\u03bf\u03b9\u03b5\u03af\u03c4\u03b1\u03b9 \u03b5\u03c5\u03c1\u03ad\u03c9\u03c2 \u03c3\u03c4\u03b7 \u03bc\u03b1\u03b3\u03b5\u03b9\u03c1\u03b9\u03ba\u03ae, \u03b9\u03b4\u03b9\u03b1\u03af\u03c4\u03b5\u03c1\u03b1 \u03c3\u03c4\u03b1 \u03c8\u03b7\u03c4\u03ac \u03ba\u03b1\u03b9 \u03c3\u03c4\u03b9\u03c2 \u03bc\u03b1\u03c1\u03b9\u03bd\u03ac\u03b4\u03b5\u03c2.","\u0391\u03c0\u03b1\u03b9\u03c4\u03b5\u03af \u03c0\u03bb\u03ae\u03c1\u03b7 \u03ad\u03ba\u03b8\u03b5\u03c3\u03b7 \u03c3\u03c4\u03bf\u03bd \u03ae\u03bb\u03b9\u03bf \u03ba\u03b1\u03b9 \u03ba\u03b1\u03bb\u03ae \u03b1\u03c0\u03bf\u03c3\u03c4\u03c1\u03ac\u03b3\u03b3\u03b9\u03c3\u03b7. \u0395\u03af\u03bd\u03b1\u03b9 \u03b1\u03bd\u03b8\u03b5\u03ba\u03c4\u03b9\u03ba\u03cc \u03c3\u03c4\u03b7\u03bd \u03be\u03b7\u03c1\u03b1\u03c3\u03af\u03b1, \u03bc\u03b5 \u03c7\u03b1\u03bc\u03b7\u03bb\u03ad\u03c2 \u03b1\u03bd\u03ac\u03b3\u03ba\u03b5\u03c2 \u03c3\u03b5 \u03bd\u03b5\u03c1\u03cc. \u0395\u03c5\u03b4\u03bf\u03ba\u03b9\u03bc\u03b5\u03af \u03b9\u03ba\u03b1\u03bd\u03bf\u03c0\u03bf\u03b9\u03b7\u03c4\u03b9\u03ba\u03ac \u03c3\u03b5 \u03c6\u03c4\u03c9\u03c7\u03ac \u03b5\u03b4\u03ac\u03c6\u03b7."],t.li)
